import java.util.PriorityQueue;
import java.util.HashSet;
import java.util.Set;

public class Solution {
    public static long solve(long[] value, long[] limit) {
        int n = value.length;
        PriorityQueue<long[]> heap = new PriorityQueue<>((a, b) -> {
            long valDiff = -a[0] + b[0];
            if (valDiff != 0) return (int) valDiff;
            return (int) (a[1] - b[1]);
        });

        for (int i = 0; i < n; i++) {
            heap.offer(new long[]{-value[i], limit[i]});
        }

        int activeCount = 0;
        long totalSum = 0;
        Set<Integer> inactiveSet = new HashSet<>();

        while (!heap.isEmpty()) {
            long[] current = heap.poll();
            long val = -current[0];
            long lim = current[1];

            if (activeCount < lim && !inactiveSet.contains(val)) {
                totalSum += val;
                activeCount++;

                for (int i = 0; i < n; i++) {
                    if (!inactiveSet.contains(i) && limit[i] <= activeCount) {
                        inactiveSet.add(i);
                    }
                }
            }
        }

        return totalSum;
    }
}
